        const EAL_MdMethod *hashMethod512 = EAL_MdFindDefaultMethod(CRYPT_MD_SHA512);
        hashMethod256->freeCtx(ctx->sha256MdCtx);
        hashMethod512->freeCtx(ctx->sha512MdCtx);
        ctx->sha256MdCtx = NULL;
        ctx->sha512MdCtx = NULL;
